 Begin CmpMap 	# Compound Mapping
    Nin = 1 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    InvB = 1 	# Second Mapping used in inverse direction
    MapA = 	# First component Mapping
       Begin CmpMap 	# Compound Mapping
          Nin = 1 	# Number of input coordinates
          IsSimp = 1 	# Mapping has been simplified
       IsA Mapping 	# Mapping between coordinate systems
          MapA = 	# First component Mapping
             Begin TimeMap 	# Conversion between time coordinate systems
                Nin = 1 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                Ntime = 3 	# Number of conversion steps
                Time1 = "BEPTOMJD" 	# Convert Besselian epoch to MJD
                Time1a = 0 	# Besselian epoch offset
                Time1b = -678940.36416390003 	# MJD offset
                Time1c = 678940.36416390003 	# Combined forward offset
                Time1d = -1858.8771134054914 	# Combined inverse offset
                Time2 = "TTTOTAI" 	# Convert TT to TAI
                Time2a = -678940.36416390003 	# MJD offset
                Time3 = "MJDTOJEP" 	# Convert MJD to Julian epoch
                Time3a = -678940.36416390003 	# MJD offset
                Time3b = 99.999998980150394 	# Julian epoch offset
                Time3c = -1958.8374094220396 	# Combined forward offset
                Time3d = 715465.36379139998 	# Combined inverse offset
             End TimeMap
          MapB = 	# Second component Mapping
             Begin ZoomMap 	# Zoom about the origin
                Nin = 1 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                Zoom = 365.25 	# Zoom factor
             End ZoomMap
       End CmpMap
    MapB = 	# Second component Mapping
       Begin ShiftMap 	# Shift each coordinate axis
          Nin = 1 	# Number of input coordinates
          Invert = 1 	# Mapping inverted
       IsA Mapping 	# Mapping between coordinate systems
          Sft1 = 0.00037250006846534234 	# Shift for axis 1
       End ShiftMap
 End CmpMap
